__kernel void dynproc_kernel(
    const int pyramid_height,
    __global const int* wall,
    __global int* src,
    __global int* dst,
    const int cols,
    const int rows,
    const int t,
    const int borderCols,
    const int theHalo,
    __local int* localSrc1,
    __local int* localSrc2,
    __global int* outputBuffer)
{
    int n = get_global_id(0);
    if (n >= cols) return;

    int min_val;
    int idx = n;

    for (int i = 0; i < pyramid_height && (t + i) < (rows - 1); i++) {
        barrier(CLK_LOCAL_MEM_FENCE);

        // Load src into local memory
        localSrc1[n] = src[n];
        barrier(CLK_LOCAL_MEM_FENCE);

        min_val = localSrc1[n];
        if (n > 0)
            min_val = min(min_val, localSrc1[n - 1]);
        if (n < cols - 1)
            min_val = min(min_val, localSrc1[n + 1]);

        int wall_val = wall[(t + i + 1) * cols + n];
        int val = wall_val + min_val;

        dst[n] = val;

        // Swap src and dst pointers for next iteration
        __global int* tmp = src;
        src = dst;
        dst = tmp;
    }

    // Write final result to outputBuffer for debugging or other use
    if (n < 16384) {
        outputBuffer[n] = src[n];
    }
}
